@app.post("/enable-mfa")
@login_required
def enable_mfa():
    user = get_current_user()
    if user["mfa_enabled"]:
        return jsonify({"message": "mfa_already_enabled", "user": public_user(user)})

    user["mfa_enabled"] = True
    user["mfa_secret"] = secrets.token_urlsafe(16)
    user["account_recovery_pending"] = False
    user["latest_mfa_reset_token"] = None
    user["latest_mfa_reset_issued_at"] = None
    return jsonify({
        "message": "mfa_enabled",
        "mfa_secret": user["mfa_secret"],
        "user": public_user(user)
    })

@app.post("/disable-mfa")
@login_required
def disable_mfa():
    user = get_current_user()
    user["mfa_enabled"] = False
    user["mfa_secret"] = None
    user["account_recovery_pending"] = False
    user["latest_mfa_reset_token"] = None
    user["latest_mfa_reset_issued_at"] = None
    return jsonify({"message": "mfa_disabled", "user": public_user(user)})

@app.post("/reset-mfa")
def reset_mfa():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()

    if not email:
        return jsonify({"error": "email_required"}), 400

    user = next((u for u in users.values() if u["email"] == email), None)

    if user:
        token = generate_reset_token(user)
        reset_link = url_for("consume_mfa_reset", token=token, _external=True)
        body = (
            f"We received a request to reset MFA for your account.\n\n"
            f"If you requested this, use the following link to disable MFA and recover access:\n"
            f"{reset_link}\n\n"
            f"This link expires in {app.config['RESET_TOKEN_MAX_AGE_SECONDS']} seconds."
        )
        send_email(user["email"], "Reset your MFA", body)

    return jsonify({
        "message": "if_account_exists_reset_email_sent"
    })

@app.get("/reset-mfa/consume")
def consume_mfa_reset():
    token = request.args.get("token", "")

    if not token:
        return jsonify({"error": "token_required"}), 400

    try:
        data = verify_reset_token(token, app.config["RESET_TOKEN_MAX_AGE_SECONDS"])
    except SignatureExpired:
        return jsonify({"error": "token_expired"}), 400
    except BadSignature:
        return jsonify({"error": "invalid_token"}), 400

    user = users.get(data["user_id"])
    if not user:
        return jsonify({"error": "invalid_token"}), 400

    if user["email"] != data.get("email"):
        return jsonify({"error": "invalid_token"}), 400

    if user.get("latest_mfa_reset_token") != token:
        return jsonify({"error": "token_superseded_or_used"}), 400

    user["mfa_enabled"] = False
    user["mfa_secret"] = None
    user["account_recovery_pending"] = True
    user["latest_mfa_reset_token"] = None
    user["latest_mfa_reset_issued_at"] = None

    return jsonify({
        "message": "mfa_reset_complete",
        "password_only_login_enabled": True,
        "user": public_user(user)
    })

